'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes } from 'react'
import styles from './kbd.module.css'

export interface KbdProps extends HTMLAttributes<HTMLElement> {
  size?: 'sm' | 'md'
}

export function Kbd({ size = 'md', className, children, ...props }: KbdProps) {
  return (
    <kbd data-size={size} className={cn(styles['kbd'], className)} {...props}>
      {children}
    </kbd>
  )
}

@layer cascivo.component {
  .kbd {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    font-family: var(--cascivo-font-mono);
    font-weight: var(--cascivo-font-medium);
    line-height: 1;
    color: var(--cascivo-color-text-subtle);
    background-color: var(--cascivo-color-surface-raised);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-indicator);
    box-shadow: inset 0 -1px 0 var(--cascivo-color-border-strong);
    white-space: nowrap;

    &[data-size='sm'] {
      min-inline-size: 1.25rem;
      padding-block: var(--cascivo-space-0);
      padding-inline: var(--cascivo-space-1);
      font-size: var(--cascivo-text-xs);
      block-size: 1.25rem;
    }

    &[data-size='md'] {
      min-inline-size: 1.5rem;
      padding-block: var(--cascivo-space-1);
      padding-inline: var(--cascivo-space-2);
      font-size: var(--cascivo-text-sm);
      block-size: 1.5rem;
    }
  }
}
